@startuml
title RECYCLER VIEW ADAPTER's Class Diagram

skinparam packageStyle rectangle
skinparam shadowing false
skinparam classAttributeIconSize 0

package "androidx" {
  package "recyclerview" {
    package "widget" {
      class "RecyclerView.Adapter" as RVAdapter
    }
  }
}

package "com" {
  package "example" {
    package "simple_chat" {
      package "recycler_view_adapter" {

        class ChatAdapter {
          + mData : List<RecordInfo>
          - headerOfMy : Bitmap
          - headerOfSystem : Bitmap
          - intent : Intent
          - mapOfImage : HashMap<String, Bitmap>
          - settingInfo : SharedPreferences
          --
          + ChatAdapter()
          + getItemCount()
          + getItemViewType()
          + onBindViewHolder()
          + onCreateViewHolder()
          + updateHeader()
          - setHeaderImage()
        }

        package "MyService" {
          class MusicInfoBinder
        }

        ChatAdapter o-- MusicInfoBinder : binder
      }
    }
  }
}

ChatAdapter -up-|> RVAdapter

@enduml
